8	#include "firmware.h"
9	
10	uint32_t *irq(uint32_t *regs, uint32_t irqs)
11	{
12		static unsigned int ext_irq_4_count = 0;
13		static unsigned int ext_irq_5_count = 0;
14		static unsigned int timer_irq_count = 0;
15	
16		// checking compressed isa q0 reg handling
17		if ((irqs & 6) != 0) {
18			uint32_t pc = (regs[0] & 1) ? regs[0] - 3 : regs[0] - 4;
19			uint32_t instr = *(uint16_t*)pc;
20	
21			if ((instr & 3) == 3)
22				instr = instr | (*(uint16_t*)(pc + 2)) << 16;
23	
24			if (((instr & 3) != 3) != (regs[0] & 1)) {
25				print_str("Mismatch between q0 LSB and decoded instruction word! q0=0x");
26				print_hex(regs[0], 8);
27				print_str(", instr=0x");
28				if ((instr & 3) == 3)
29					print_hex(instr, 8);
30				else
31					print_hex(instr, 4);
32				print_str("\n");
33				__asm__ volatile ("ebreak");
34			}
35		}
36	
37		if ((irqs & (1<<4)) != 0) {
38			ext_irq_4_count++;
39			// print_str("[EXT-IRQ-4]");
40		}
41	
42		if ((irqs & (1<<5)) != 0) {
43			ext_irq_5_count++;
44			// print_str("[EXT-IRQ-5]");
45		}
46	
47		if ((irqs & 1) != 0) {
48			timer_irq_count++;
49			// print_str("[TIMER-IRQ]");
50		}
51	
52		if ((irqs & 6) != 0)
53		{
54			uint32_t pc = (regs[0] & 1) ? regs[0] - 3 : regs[0] - 4;
55			uint32_t instr = *(uint16_t*)pc;
56	
57			if ((instr & 3) == 3)
58				instr = instr | (*(uint16_t*)(pc + 2)) << 16;
59	
60			print_str("\n");
61			print_str("------------------------------------------------------------\n");
62	
63			if ((irqs & 2) != 0) {
64				if (instr == 0x00100073 || instr == 0x9002) {
65					print_str("EBREAK instruction at 0x");
66					print_hex(pc, 8);
67					print_str("\n");
68				} else {
69					print_str("Illegal Instruction at 0x");
70					print_hex(pc, 8);
71					print_str(": 0x");
72					print_hex(instr, ((instr & 3) == 3) ? 8 : 4);
73					print_str("\n");
74				}
75			}
76	
77			if ((irqs & 4) != 0) {
78				print_str("Bus error in Instruction at 0x");
79				print_hex(pc, 8);
80				print_str(": 0x");
81				print_hex(instr, ((instr & 3) == 3) ? 8 : 4);
82				print_str("\n");
83			}
84	
85			for (int i = 0; i < 8; i++)
86			for (int k = 0; k < 4; k++)
87			{
88				int r = i + k*8;
89	
90				if (r == 0) {
91					print_str("pc  ");
92				} else
93				if (r < 10) {
94					print_chr('x');
95					print_chr('0' + r);
96					print_chr(' ');
97					print_chr(' ');
98				} else
99				if (r < 20) {
100					print_chr('x');
101					print_chr('1');
102					print_chr('0' + r - 10);
103					print_chr(' ');
104				} else
105				if (r < 30) {
106					print_chr('x');
107					print_chr('2');
108					print_chr('0' + r - 20);
109					print_chr(' ');
110				} else {
111					print_chr('x');
112					print_chr('3');
113					print_chr('0' + r - 30);
114					print_chr(' ');
115				}
116	
117				print_hex(regs[r], 8);
118				print_str(k == 3 ? "\n" : "    ");
119			}
120	
121			print_str("------------------------------------------------------------\n");
122	
123			print_str("Number of fast external IRQs counted: ");
124			print_dec(ext_irq_4_count);
125			print_str("\n");
126	
127			print_str("Number of slow external IRQs counted: ");
128			print_dec(ext_irq_5_count);
129			print_str("\n");
130	
131			print_str("Number of timer IRQs counted: ");
132			print_dec(timer_irq_count);
133			print_str("\n");
134	
135			__asm__ volatile ("ebreak");
136		}
137	
138		return regs;
139	}
