8	#include "firmware.h"
9	
10	#define OUTPORT 0x10000000
11	
12	void print_chr(char ch)
13	{
14		*((volatile uint32_t*)OUTPORT) = ch;
15	}
16	
17	void print_str(const char *p)
18	{
19		while (*p != 0)
20			*((volatile uint32_t*)OUTPORT) = *(p++);
21	}
22	
23	void print_dec(unsigned int val)
24	{
25		char buffer[10];
26		char *p = buffer;
27		while (val || p == buffer) {
28			*(p++) = val % 10;
29			val = val / 10;
30		}
31		while (p != buffer) {
32			*((volatile uint32_t*)OUTPORT) = '0' + *(--p);
33		}
34	}
35	
36	void print_hex(unsigned int val, int digits)
37	{
38		for (int i = (4*digits)-4; i >= 0; i -= 4)
39			*((volatile uint32_t*)OUTPORT) = "0123456789ABCDEF"[(val >> i) % 16];
40	}
