10	static uint32_t xorshift32(void) {
11		static uint32_t x = 314159265;
12		x ^= x << 13;
13		x ^= x >> 17;
14		x ^= x << 5;
15		return x;
16	}
17	
18	void multest(void)
19	{
20		for (int i = 0; i < 15; i++)
21		{
22			uint32_t a = xorshift32();
23			uint32_t b = xorshift32();
24	
25			switch (i)
26			{
27			case 0:
28				a = 0x80000000;
29				b = 0xFFFFFFFF;
30				break;
31			case 1:
32				a = 0;
33				b = 0;
34				break;
35			case 2:
36				a |= 0x80000000;
37				b = 0;
38				break;
39			case 3:
40				a &= 0x7FFFFFFF;
41				b = 0;
42				break;
43			}
44	
45			uint64_t au = a, bu = b;
46			int64_t as = (int32_t)a, bs = (int32_t)b;
47	
48			print_str("input     [");
49			print_hex(as >> 32, 8);
50			print_str("] ");
51			print_hex(a, 8);
52			print_str(" [");
53			print_hex(bs >> 32, 8);
54			print_str("] ");
55			print_hex(b, 8);
56			print_chr('\n');
57	
58			uint32_t h_mul, h_mulh, h_mulhsu, h_mulhu;
59			print_str("hard mul   ");
60	
61			h_mul = hard_mul(a, b);
62			print_hex(h_mul, 8);
63			print_str("  ");
64	
65			h_mulh = hard_mulh(a, b);
66			print_hex(h_mulh, 8);
67			print_str("  ");
68	
69			h_mulhsu = hard_mulhsu(a, b);
70			print_hex(h_mulhsu, 8);
71			print_str("  ");
72	
73			h_mulhu = hard_mulhu(a, b);
74			print_hex(h_mulhu, 8);
75			print_chr('\n');
76	
77			uint32_t s_mul, s_mulh, s_mulhsu, s_mulhu;
78			print_str("soft mul   ");
79	
80			s_mul = a * b;
81			print_hex(s_mul, 8);
82			print_str("  ");
83	
84			s_mulh = (as * bs) >> 32;
85			print_hex(s_mulh, 8);
86			print_str("  ");
87	
88			s_mulhsu = (as * bu) >> 32;
89			print_hex(s_mulhsu, 8);
90			print_str("  ");
91	
92			s_mulhu = (au * bu) >> 32;
93			print_hex(s_mulhu, 8);
94			print_str("  ");
95	
96			if (s_mul != h_mul || s_mulh != h_mulh || s_mulhsu != h_mulhsu || s_mulhu != h_mulhu) {
97				print_str("ERROR!\n");
98				__asm__ volatile ("ebreak");
99				return;
100			}
101	
102			print_str(" OK\n");
103	
104			uint32_t h_div, h_divu, h_rem, h_remu;
105			print_str("hard div   ");
106	
107			h_div = hard_div(a, b);
108			print_hex(h_div, 8);
109			print_str("  ");
110	
111			h_divu = hard_divu(a, b);
112			print_hex(h_divu, 8);
113			print_str("  ");
114	
115			h_rem = hard_rem(a, b);
116			print_hex(h_rem, 8);
117			print_str("  ");
118	
119			h_remu = hard_remu(a, b);
120			print_hex(h_remu, 8);
121			print_chr('\n');
122	
123			uint32_t s_div, s_divu, s_rem, s_remu;
124			print_str("soft div   ");
125	
126			s_div = b ? as / bs : 0xffffffff;
127			print_hex(s_div, 8);
128			print_str("  ");
129	
130			s_divu = b ? au / bu : 0xffffffff;
131			print_hex(s_divu, 8);
132			print_str("  ");
133	
134			s_rem = b ? as % bs : a;
135			print_hex(s_rem, 8);
136			print_str("  ");
137	
138			s_remu = b ? au % bu : a;
139			print_hex(s_remu, 8);
140			print_str("  ");
141	
142			if (s_div != h_div || s_divu != h_divu || s_rem != h_rem || s_remu != h_remu) {
143				print_str("ERROR!\n");
144				__asm__ volatile ("ebreak");
145				return;
146			}
147	
148			print_str(" OK\n");
149		}
150	}
