8	// A simple Sieve of Eratosthenes
9	
10	#include "firmware.h"
11	
12	#define BITMAP_SIZE 64
13	
14	static uint32_t bitmap[BITMAP_SIZE/32];
15	static uint32_t hash;
16	
17	static uint32_t mkhash(uint32_t a, uint32_t b)
18	{
19		// The XOR version of DJB2
20		return ((a << 5) + a) ^ b;
21	}
22	
23	static void bitmap_set(int idx)
24	{
25		bitmap[idx/32] |= 1 << (idx % 32);
26	}
27	
28	static bool bitmap_get(int idx)
29	{
30		return (bitmap[idx/32] & (1 << (idx % 32))) != 0;
31	}
32	
33	static void print_prime(int idx, int val)
34	{
35		if (idx < 10)
36			print_str(" ");
37		print_dec(idx);
38		if (idx / 10 == 1)
39			goto force_th;
40		switch (idx % 10) {
41			case 1: print_str("st"); break;
42			case 2: print_str("nd"); break;
43			case 3: print_str("rd"); break;
44		force_th:
45			default: print_str("th"); break;
46		}
47		print_str(" prime is ");
48		print_dec(val);
49		print_str(".\n");
50	
51		hash = mkhash(hash, idx);
52		hash = mkhash(hash, val);
53	}
54	
55	void sieve(void)
56	{
57		int idx = 1;
58		hash = 5381;
59		print_prime(idx++, 2);
60		for (int i = 0; i < BITMAP_SIZE; i++) {
61			if (bitmap_get(i))
62				continue;
63			print_prime(idx++, 3+2*i);
64			for (int j = 2*(3+2*i);; j += 3+2*i) {
65				if (j%2 == 0)
66					continue;
67				int k = (j-3)/2;
68				if (k >= BITMAP_SIZE)
69					break;
70				bitmap_set(k);
71			}
72		}
73	
74		print_str("checksum: ");
75		print_hex(hash, 8);
76	
77		if (hash == 0x1772A48F) {
78			print_str(" OK\n");
79		} else {
80			print_str(" ERROR\n");
81			__asm__ volatile ("ebreak");
82		}
83	}
