10	static void stats_print_dec(unsigned int val, int digits, bool zero_pad)
11	{
12		char buffer[32];
13		char *p = buffer;
14		while (val || digits > 0) {
15			if (val)
16				*(p++) = '0' + val % 10;
17			else
18				*(p++) = zero_pad ? '0' : ' ';
19			val = val / 10;
20			digits--;
21		}
22		while (p != buffer) {
23			if (p[-1] == ' ' && p[-2] == ' ') p[-1] = '.';
24			print_chr(*(--p));
25		}
26	}
27	
28	void stats(void)
29	{
30		unsigned int num_cycles, num_instr;
31		__asm__ volatile ("rdcycle %0; rdinstret %1;" : "=r"(num_cycles), "=r"(num_instr));
32		print_str("Cycle counter ........");
33		stats_print_dec(num_cycles, 8, false);
34		print_str("\nInstruction counter ..");
35		stats_print_dec(num_instr, 8, false);
36		print_str("\nCPI: ");
37		stats_print_dec((num_cycles / num_instr), 0, false);
38		print_str(".");
39		stats_print_dec(((100 * num_cycles) / num_instr) % 100, 2, true);
40		print_str("\n");
41	}
