151		always @(negedge clk) begin
152			xfer_io0_90 <= xfer_io0_do;
153			xfer_io1_90 <= xfer_io1_do;
154			xfer_io2_90 <= xfer_io2_do;
155			xfer_io3_90 <= xfer_io3_do;
156		end
157	
158		assign flash_csb = config_en ? xfer_csb : config_csb;
159		assign flash_clk = config_en ? xfer_clk : config_clk;
160	
161		assign flash_io0_oe = config_en ? xfer_io0_oe : config_oe[0];
162		assign flash_io1_oe = config_en ? xfer_io1_oe : config_oe[1];
163		assign flash_io2_oe = config_en ? xfer_io2_oe : config_oe[2];
164		assign flash_io3_oe = config_en ? xfer_io3_oe : config_oe[3];
165	
166		assign flash_io0_do = config_en ? (config_ddr ? xfer_io0_90 : xfer_io0_do) : config_do[0];
167		assign flash_io1_do = config_en ? (config_ddr ? xfer_io1_90 : xfer_io1_do) : config_do[1];
168		assign flash_io2_do = config_en ? (config_ddr ? xfer_io2_90 : xfer_io2_do) : config_do[2];
169		assign flash_io3_do = config_en ? (config_ddr ? xfer_io3_90 : xfer_io3_do) : config_do[3];
170	
171		wire xfer_dspi = din_ddr && !din_qspi;
172		wire xfer_ddr = din_ddr && din_qspi;
173	
174		spimemio_xfer xfer (
175			.clk          (clk         ),
176			.resetn       (xfer_resetn ),
177			.din_valid    (din_valid   ),
178			.din_ready    (din_ready   ),
179			.din_data     (din_data    ),
180			.din_tag      (din_tag     ),
181			.din_cont     (din_cont    ),
182			.din_dspi     (xfer_dspi   ),
183			.din_qspi     (din_qspi    ),
184			.din_ddr      (xfer_ddr    ),
185			.din_rd       (din_rd      ),
186			.dout_valid   (dout_valid  ),
187			.dout_data    (dout_data   ),
188			.dout_tag     (dout_tag    ),
189			.flash_csb    (xfer_csb    ),
190			.flash_clk    (xfer_clk    ),
191			.flash_io0_oe (xfer_io0_oe ),
192			.flash_io1_oe (xfer_io1_oe ),
193			.flash_io2_oe (xfer_io2_oe ),
194			.flash_io3_oe (xfer_io3_oe ),
195			.flash_io0_do (xfer_io0_do ),
196			.flash_io1_do (xfer_io1_do ),
197			.flash_io2_do (xfer_io2_do ),
198			.flash_io3_do (xfer_io3_do ),
199			.flash_io0_di (flash_io0_di),
200			.flash_io1_di (flash_io1_di),
201			.flash_io2_di (flash_io2_di),
202			.flash_io3_di (flash_io3_di)
203		);
204	
205		reg [3:0] state;
206	
207		always @(posedge clk) begin
208			xfer_resetn <= 1;
209			din_valid <= 0;
210	
211			if (!resetn || softreset) begin
212				state <= 0;
213				xfer_resetn <= 0;
214				rd_valid <= 0;
215				din_tag <= 0;
216				din_cont <= 0;
217				din_qspi <= 0;
218				din_ddr <= 0;
219				din_rd <= 0;
220			end else begin
221				if (dout_valid && dout_tag == 1) buffer[ 7: 0] <= dout_data;
222				if (dout_valid && dout_tag == 2) buffer[15: 8] <= dout_data;
223				if (dout_valid && dout_tag == 3) buffer[23:16] <= dout_data;
224				if (dout_valid && dout_tag == 4) begin
225					rdata <= {dout_data, buffer};
226					rd_addr <= rd_inc ? rd_addr + 4 : addr;
227					rd_valid <= 1;
228					rd_wait <= rd_inc;
229					rd_inc <= 1;
230				end
231	
232				if (valid)
233					rd_wait <= 0;
234	
235				case (state)
236					0: begin
237						din_valid <= 1;
238						din_data <= 8'h ff;
239						din_tag <= 0;
240						if (din_ready) begin
241							din_valid <= 0;
242							state <= 1;
243						end
244					end
245					1: begin
246						if (dout_valid) begin
247							xfer_resetn <= 0;
248							state <= 2;
249						end
250					end
251					2: begin
252						din_valid <= 1;
253						din_data <= 8'h ab;
254						din_tag <= 0;
255						if (din_ready) begin
256							din_valid <= 0;
257							state <= 3;
258						end
259					end
260					3: begin
261						if (dout_valid) begin
262							xfer_resetn <= 0;
263							state <= 4;
264						end
265					end
266					4: begin
267						rd_inc <= 0;
268						din_valid <= 1;
269						din_tag <= 0;
270						case ({config_ddr, config_qspi})
271							2'b11: din_data <= 8'h ED;
272							2'b01: din_data <= 8'h EB;
273							2'b10: din_data <= 8'h BB;
274							2'b00: din_data <= 8'h 03;
275						endcase
276						if (din_ready) begin
277							din_valid <= 0;
278							state <= 5;
279						end
280					end
281					5: begin
282						if (valid && !ready) begin
283							din_valid <= 1;
284							din_tag <= 0;
285							din_data <= addr[23:16];
286							din_qspi <= config_qspi;
287							din_ddr <= config_ddr;
288							if (din_ready) begin
289								din_valid <= 0;
290								state <= 6;
291							end
292						end
293					end
294					6: begin
295						din_valid <= 1;
296						din_tag <= 0;
297						din_data <= addr[15:8];
298						if (din_ready) begin
299							din_valid <= 0;
300							state <= 7;
301						end
302					end
303					7: begin
304						din_valid <= 1;
305						din_tag <= 0;
306						din_data <= addr[7:0];
307						if (din_ready) begin
308							din_valid <= 0;
309							din_data <= 0;
310							state <= config_qspi || config_ddr ? 8 : 9;
311						end
312					end
313					8: begin
314						din_valid <= 1;
315						din_tag <= 0;
316						din_data <= config_cont ? 8'h A5 : 8'h FF;
317						if (din_ready) begin
318							din_rd <= 1;
319							din_data <= config_dummy;
320							din_valid <= 0;
321							state <= 9;
322						end
323					end
324					9: begin
325						din_valid <= 1;
326						din_tag <= 1;
327						if (din_ready) begin
328							din_valid <= 0;
329							state <= 10;
330						end
331					end
332					10: begin
333						din_valid <= 1;
334						din_data <= 8'h 00;
335						din_tag <= 2;
336						if (din_ready) begin
337							din_valid <= 0;
338							state <= 11;
339						end
340					end
341					11: begin
342						din_valid <= 1;
343						din_tag <= 3;
344						if (din_ready) begin
345							din_valid <= 0;
346							state <= 12;
347						end
348					end
349					12: begin
350						if (!rd_wait || valid) begin
351							din_valid <= 1;
352							din_tag <= 4;
353							if (din_ready) begin
354								din_valid <= 0;
355								state <= 9;
356							end
357						end
358					end
359				endcase
360	
361				if (jump) begin
362					rd_inc <= 0;
363					rd_valid <= 0;
364					xfer_resetn <= 0;
365					if (config_cont) begin
366						state <= 5;
367					end else begin
368						state <= 4;
369						din_qspi <= 0;
370						din_ddr <= 0;
371					end
372					din_rd <= 0;
373				end
374			end
375		end
376	endmodule
