378	module spimemio_xfer (
379		input clk, resetn,
380	
381		input            din_valid,
382		output           din_ready,
383		input      [7:0] din_data,
384		input      [3:0] din_tag,
385		input            din_cont,
386		input            din_dspi,
387		input            din_qspi,
388		input            din_ddr,
389		input            din_rd,
390	
391		output           dout_valid,
392		output     [7:0] dout_data,
393		output     [3:0] dout_tag,
394	
395		output reg flash_csb,
396		output reg flash_clk,
397	
398		output reg flash_io0_oe,
399		output reg flash_io1_oe,
400		output reg flash_io2_oe,
401		output reg flash_io3_oe,
402	
403		output reg flash_io0_do,
404		output reg flash_io1_do,
405		output reg flash_io2_do,
406		output reg flash_io3_do,
407	
408		input      flash_io0_di,
409		input      flash_io1_di,
410		input      flash_io2_di,
411		input      flash_io3_di
412	);
413		reg [7:0] obuffer;
414		reg [7:0] ibuffer;
415	
416		reg [3:0] count;
417		reg [3:0] dummy_count;
418	
419		reg xfer_cont;
420		reg xfer_dspi;
421		reg xfer_qspi;
422		reg xfer_ddr;
423		reg xfer_ddr_q;
424		reg xfer_rd;
425		reg [3:0] xfer_tag;
426		reg [3:0] xfer_tag_q;
427	
428		reg [7:0] next_obuffer;
429		reg [7:0] next_ibuffer;
430		reg [3:0] next_count;
431	
432		reg fetch;
433		reg next_fetch;
434		reg last_fetch;
435	
436		always @(posedge clk) begin
437			xfer_ddr_q <= xfer_ddr;
438			xfer_tag_q <= xfer_tag;
439		end
440	
441		assign din_ready = din_valid && resetn && next_fetch;
442	
443		assign dout_valid = (xfer_ddr_q ? fetch && !last_fetch : next_fetch && !fetch) && resetn;
444		assign dout_data = ibuffer;
445		assign dout_tag = xfer_tag_q;
446	
447		always @* begin
448			flash_io0_oe = 0;
449			flash_io1_oe = 0;
450			flash_io2_oe = 0;
451			flash_io3_oe = 0;
452	
453			flash_io0_do = 0;
454			flash_io1_do = 0;
455			flash_io2_do = 0;
456			flash_io3_do = 0;
457	
458			next_obuffer = obuffer;
459			next_ibuffer = ibuffer;
460			next_count = count;
461			next_fetch = 0;
462	
463			if (dummy_count == 0) begin
464				casez ({xfer_ddr, xfer_qspi, xfer_dspi})
465					3'b 000: begin
466						flash_io0_oe = 1;
467						flash_io0_do = obuffer[7];
468	
469						if (flash_clk) begin
470							next_obuffer = {obuffer[6:0], 1'b 0};
471							next_count = count - |count;
472						end else begin
473							next_ibuffer = {ibuffer[6:0], flash_io1_di};
474						end
475	
476						next_fetch = (next_count == 0);
477					end
478					3'b 01?: begin
479						flash_io0_oe = !xfer_rd;
480						flash_io1_oe = !xfer_rd;
481						flash_io2_oe = !xfer_rd;
482						flash_io3_oe = !xfer_rd;
483	
484						flash_io0_do = obuffer[4];
485						flash_io1_do = obuffer[5];
486						flash_io2_do = obuffer[6];
487						flash_io3_do = obuffer[7];
488	
489						if (flash_clk) begin
490							next_obuffer = {obuffer[3:0], 4'b 0000};
491							next_count = count - {|count, 2'b00};
492						end else begin
493							next_ibuffer = {ibuffer[3:0], flash_io3_di, flash_io2_di, flash_io1_di, flash_io0_di};
494						end
495	
496						next_fetch = (next_count == 0);
497					end
498					3'b 11?: begin
499						flash_io0_oe = !xfer_rd;
500						flash_io1_oe = !xfer_rd;
501						flash_io2_oe = !xfer_rd;
502						flash_io3_oe = !xfer_rd;
503	
504						flash_io0_do = obuffer[4];
505						flash_io1_do = obuffer[5];
506						flash_io2_do = obuffer[6];
507						flash_io3_do = obuffer[7];
508	
509						next_obuffer = {obuffer[3:0], 4'b 0000};
510						next_ibuffer = {ibuffer[3:0], flash_io3_di, flash_io2_di, flash_io1_di, flash_io0_di};
511						next_count = count - {|count, 2'b00};
512	
513						next_fetch = (next_count == 0);
514					end
515					3'b ??1: begin
516						flash_io0_oe = !xfer_rd;
517						flash_io1_oe = !xfer_rd;
518	
519						flash_io0_do = obuffer[6];
520						flash_io1_do = obuffer[7];
521	
522						if (flash_clk) begin
523							next_obuffer = {obuffer[5:0], 2'b 00};
524							next_count = count - {|count, 1'b0};
525						end else begin
526							next_ibuffer = {ibuffer[5:0], flash_io1_di, flash_io0_di};
527						end
528	
529						next_fetch = (next_count == 0);
530					end
531				endcase
532			end
533		end
534	
535		always @(posedge clk) begin
536			if (!resetn) begin
537				fetch <= 1;
538				last_fetch <= 1;
539				flash_csb <= 1;
540				flash_clk <= 0;
541				count <= 0;
542				dummy_count <= 0;
543				xfer_tag <= 0;
544				xfer_cont <= 0;
545				xfer_dspi <= 0;
546				xfer_qspi <= 0;
547				xfer_ddr <= 0;
548				xfer_rd <= 0;
549			end else begin
550				fetch <= next_fetch;
551				last_fetch <= xfer_ddr ? fetch : 1;
552				if (dummy_count) begin
553					flash_clk <= !flash_clk && !flash_csb;
554					dummy_count <= dummy_count - flash_clk;
555				end else
556				if (count) begin
557					flash_clk <= !flash_clk && !flash_csb;
558					obuffer <= next_obuffer;
559					ibuffer <= next_ibuffer;
560					count <= next_count;
561				end
562				if (din_valid && din_ready) begin
563					flash_csb <= 0;
564					flash_clk <= 0;
565	
566					count <= 8;
567					dummy_count <= din_rd ? din_data : 0;
568					obuffer <= din_data;
569	
570					xfer_tag <= din_tag;
571					xfer_cont <= din_cont;
572					xfer_dspi <= din_dspi;
573					xfer_qspi <= din_qspi;
574					xfer_ddr <= din_ddr;
575					xfer_rd <= din_rd;
576				end
577			end
578		end
579	endmodule
