45	void flashio(uint8_t *data, int len, uint8_t wrencmd)
46	{
47		uint32_t func[&flashio_worker_end - &flashio_worker_begin];
48	
49		uint32_t *src_ptr = &flashio_worker_begin;
50		uint32_t *dst_ptr = func;
51	
52		while (src_ptr != &flashio_worker_end)
53			*(dst_ptr++) = *(src_ptr++);
