59	void set_flash_qspi_flag()
60	{
61		uint8_t buffer[8];
62		uint32_t addr_cr1v = 0x800002;
63	
64		// Read Any Register (RDAR 65h)
65		buffer[0] = 0x65;
66		buffer[1] = addr_cr1v >> 16;
67		buffer[2] = addr_cr1v >> 8;
68		buffer[3] = addr_cr1v;
69		buffer[4] = 0; // dummy
70		buffer[5] = 0; // rdata
71		flashio(buffer, 6, 0);
72		uint8_t cr1v = buffer[5];
73	
74		// Write Enable (WREN 06h) + Write Any Register (WRAR 71h)
75		buffer[0] = 0x71;
76		buffer[1] = addr_cr1v >> 16;
77		buffer[2] = addr_cr1v >> 8;
78		buffer[3] = addr_cr1v;
79		buffer[4] = cr1v | 2; // Enable QSPI
80		flashio(buffer, 5, 0x06);
81	}
