280	uint32_t xorshift32(uint32_t *state)
281	{
282		/* Algorithm "xor" from p. 4 of Marsaglia, "Xorshift RNGs" */
283		uint32_t x = *state;
284		x ^= x << 13;
285		x ^= x >> 17;
286		x ^= x << 5;
287		*state = x;
288	
289		return x;
290	}
