292	void cmd_memtest()
293	{
294		int cyc_count = 5;
295		int stride = 256;
296		uint32_t state;
297	
298		volatile uint32_t *base_word = (uint32_t *) 0;
299		volatile uint8_t *base_byte = (uint8_t *) 0;
300	
301		print("Running memtest ");
302	
303		// Walk in stride increments, word access
304		for (int i = 1; i <= cyc_count; i++) {
305			state = i;
306	
307			for (int word = 0; word < MEM_TOTAL / sizeof(int); word += stride) {
308				*(base_word + word) = xorshift32(&state);
309			}
310	
311			state = i;
312	
313			for (int word = 0; word < MEM_TOTAL / sizeof(int); word += stride) {
314				if (*(base_word + word) != xorshift32(&state)) {
315					print(" ***FAILED WORD*** at ");
316					print_hex(4*word, 4);
317					print("\n");
318					return;
319				}
320			}
321	
322			print(".");
323		}
324	
325		// Byte access
326		for (int byte = 0; byte < 128; byte++) {
327			*(base_byte + byte) = (uint8_t) byte;
328		}
329	
330		for (int byte = 0; byte < 128; byte++) {
331			if (*(base_byte + byte) != (uint8_t) byte) {
332				print(" ***FAILED BYTE*** at ");
333				print_hex(byte, 4);
334				print("\n");
335				return;
336			}
337		}
338	
339		print(" passed\n");
340	}
