452	uint32_t cmd_benchmark(bool verbose, uint32_t *instns_p)
453	{
454		uint8_t data[256];
455		uint32_t *words = (void*)data;
456	
457		uint32_t x32 = 314159265;
458	
459		uint32_t cycles_begin, cycles_end;
460		uint32_t instns_begin, instns_end;
461		__asm__ volatile ("rdcycle %0" : "=r"(cycles_begin));
462		__asm__ volatile ("rdinstret %0" : "=r"(instns_begin));
463	
464		for (int i = 0; i < 20; i++)
465		{
466			for (int k = 0; k < 256; k++)
467			{
468				x32 ^= x32 << 13;
469				x32 ^= x32 >> 17;
470				x32 ^= x32 << 5;
471				data[k] = x32;
472			}
473	
474			for (int k = 0, p = 0; k < 256; k++)
475			{
476				if (data[k])
477					data[p++] = k;
478			}
479	
480			for (int k = 0, p = 0; k < 64; k++)
481			{
482				x32 = x32 ^ words[k];
483			}
484		}
485	
486		__asm__ volatile ("rdcycle %0" : "=r"(cycles_end));
487		__asm__ volatile ("rdinstret %0" : "=r"(instns_end));
488	
489		if (verbose)
490		{
491			print("Cycles: 0x");
492			print_hex(cycles_end - cycles_begin, 8);
493			putchar('\n');
494	
495			print("Instns: 0x");
496			print_hex(instns_end - instns_begin, 8);
497			putchar('\n');
498	
499			print("Chksum: 0x");
500			print_hex(x32, 8);
501			putchar('\n');
502		}
503	
504		if (instns_p)
505			*instns_p = instns_end - instns_begin;
506	
507		return cycles_end - cycles_begin;
508	}
