716	
717			for (int rep = 10; rep > 0; rep--)
718			{
719				print("Command> ");
720				char cmd = getchar();
721				if (cmd > 32 && cmd < 127)
722					putchar(cmd);
723				print("\n");
724	
725				switch (cmd)
726				{
727				case '1':
728					cmd_read_flash_id();
729					break;
730				case '2':
731					cmd_read_flash_regs();
732					break;
733				case '3':
734					set_flash_mode_spi();
735					break;
736				case '4':
737					set_flash_mode_dual();
738					break;
739				case '5':
740					set_flash_mode_quad();
741					break;
742				case '6':
743					set_flash_mode_qddr();
744					break;
745				case '7':
746					reg_spictrl = reg_spictrl ^ 0x00100000;
747					break;
748				case '9':
749					cmd_benchmark(true, 0);
750					break;
751				case '0':
752					cmd_benchmark_all();
753					break;
754				case 'M':
755					cmd_memtest();
756					break;
757				case 'S':
758					cmd_print_spi_state();
759					break;
760				case 'e':
761					cmd_echo();
762					break;
