4	int main(int argc, char **argv, char **env)
5	{
6		printf("Built with %s %s.\n", Verilated::productName(), Verilated::productVersion());
7		printf("Recommended: Verilator 4.0 or later.\n");
8	
9		Verilated::commandArgs(argc, argv);
10		Vpicorv32_wrapper* top = new Vpicorv32_wrapper;
11	
12		// Tracing (vcd)
13		VerilatedVcdC* tfp = NULL;
14		const char* flag_vcd = Verilated::commandArgsPlusMatch("vcd");
15		if (flag_vcd && 0==strcmp(flag_vcd, "+vcd")) {
16			Verilated::traceEverOn(true);
17			tfp = new VerilatedVcdC;
18			top->trace (tfp, 99);
19			tfp->open("testbench.vcd");
20		}
21	
22		// Tracing (data bus, see showtrace.py)
23		FILE *trace_fd = NULL;
24		const char* flag_trace = Verilated::commandArgsPlusMatch("trace");
25		if (flag_trace && 0==strcmp(flag_trace, "+trace")) {
26			trace_fd = fopen("testbench.trace", "w");
27		}
28	
29		top->clk = 0;
30		int t = 0;
31		while (!Verilated::gotFinish()) {
32			if (t > 200)
33				top->resetn = 1;
34			top->clk = !top->clk;
35			top->eval();
36			if (tfp) tfp->dump (t);
37			if (trace_fd && top->clk && top->trace_valid) fprintf(trace_fd, "%9.9lx\n", top->trace_data);
38			t += 5;
39		}
40		if (tfp) tfp->close();
41		delete top;
42		exit(0);
43	}
